const staticData = $getWorkflowStaticData('global');
const offset = (staticData.lastUpdateId || 0) + 1;

// Получаем updates с правильным offset
const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.telegram.org/bot8527521201:AAHpyrPn4cig-zq0Xymt7lZ94qBIEXnYAeQ/getUpdates?limit=20&timeout=0&offset=${offset}`,
  timeout: 15000
});

const updates = (resp.result || []);

if (updates.length === 0) {
  return [{ json: { hasCommand: false } }];
}

const maxId = Math.max(...updates.map(u => u.update_id));

// Собираем команды
const commands = [];
for (const u of updates) {
  const msg = u.message;
  if (!msg || !msg.text) continue;
  const text = msg.text.trim();
  let cmd = null;
  if (text.startsWith('/report')) cmd = 'report';
  else if (text.startsWith('/status')) cmd = 'status';
  else if (text.startsWith('/rag')) cmd = 'rag';
  else if (text.startsWith('/help')) cmd = 'help';
  if (cmd) {
    commands.push({ cmd, chatId: msg.chat.id, text, update_id: u.update_id });
  }
}

// Сохраняем offset
staticData.lastUpdateId = maxId;

if (commands.length === 0) {
  return [{ json: { hasCommand: false } }];
}

const latest = commands[commands.length - 1];
return [{ json: { hasCommand: true, ...latest } }];

const items = $input.all();
const chatId = $('Parse Command').first().json.chatId;

if (items.length === 0 || !items[0].json.id) {
  return [{ json: { hasData: false, combined: '', rowIds: [], leadIds: [], count: 0, chatId } }];
}

const dateLabel = new Date().toLocaleDateString('ru-RU', { timeZone: 'Europe/Moscow' }) + ' (по запросу)';
const MAX_CHARS = 50000;
const sections = [];
let totalLen = 0;

const byLead = {};
for (const item of items) {
  const { lead_id, lead_name, curators, transcript_text, id } = item.json;
  if (!lead_id) continue;
  const lid = String(lead_id);
  if (!byLead[lid]) byLead[lid] = { lead_id: lid, lead_name: lead_name || `ФФ-${lid}`, curators: curators || '', calls: [], ids: [] };
  byLead[lid].calls.push(transcript_text || '');
  byLead[lid].ids.push(id);
}

for (const lid of Object.keys(byLead)) {
  const g = byLead[lid];
  const section = `=== LEAD-${lid} (${g.lead_name}) ===\n${g.calls.join('\n---\n')}`;
  if (totalLen + section.length > MAX_CHARS) break;
  sections.push(section);
  totalLen += section.length;
}

const combined = sections.join('\n\n');
const rowIds = Object.values(byLead).flatMap(g => g.ids).slice(0, sections.length * 5);
const leadIds = Object.keys(byLead);

return [{ json: { hasData: true, dateLabel, combined, rowIds, leadIds, count: sections.length, chatId } }];

