const meta = $('Aggregate Transcripts').first().json;
const resp = $json;
// Support both Anthropic and OpenAI response formats
let content = '';
if (resp.content && Array.isArray(resp.content)) {
  content = resp.content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim();
} else if (resp.choices?.[0]?.message) {
  const msg = resp.choices[0].message;
  content = (msg.content || msg.reasoning_content || '').trim();
}
if (!content) content = 'Сводка не получена.';
const leadList = (meta.leadIds || []).map(id => `LEAD-${id}`).join(', ') || '—';
const DIFY_URL = $env.DIFY_CHATBOT_URL || 'http://84.252.100.93:8080';
const header = `<b>📊 Промежуточный отчёт за ${meta.dateLabel}</b>\nСозвонов: ${meta.count} | Клиентов: ${(meta.leadIds||[]).length}\n<a href="${DIFY_URL}">Открыть RAG Ассистент ↗</a>`;
const digest = (header + '\n\n' + content).trim();
return [{ json: { digest, summaryText: content, rowIds: meta.rowIds, chatId: meta.chatId } }];

const text = $json.digest || '';
const max = 4000;
const chunks = [];
for (let i = 0; i < text.length; i += max) chunks.push(text.slice(i, i + max));
const chatId = $json.chatId;
return chunks.map((chunk, idx) => ({ json: { chatId, text: chunks.length > 1 ? chunk + `\n\n(${idx+1}/${chunks.length})` : chunk, rowIds: $json.rowIds } }));

